		ReadTimeout:         5 * time.Second,
		WriteTimeout:       5 * time.Second,
		MaxIdleConnDuration: 5 * time.Second,
		MaxConnsPerHost:     5,
		Dial: func(addr string) (net.Conn, error) {
			// Additional SSRF protection at connection level
			host, _, err := net.SplitHostPort(addr)
			if err != nil {
				// If SplitHostPort fails, try parsing as host without port
				host = addr
			}

			ip := net.ParseIP(host)
			if ip != nil && isPrivateIP(ip.String()) {
				return nil, fmt.Errorf("access to private IP blocked")
			}

			// Resolve hostname to check IP
			if ip == nil {
				ips, err := net.LookupIP(host)
				if err == nil && len(ips) > 0 {
					for _, resolvedIP := range ips {
						if isPrivateIP(resolvedIP.String()) {
							return nil, fmt.Errorf("access to private IP blocked")
						}
					}
				}
			}

			return fasthttp.DialTimeout(addr, 5*time.Second)
		},
	}

