// sendJSONResponse sends a JSON response with proper content type and status code
func sendJSONResponse(ctx *fasthttp.RequestCtx, resp *PreviewResponse, statusCode int) {
	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(statusCode)
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", ""
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && content != "" {
					description = content
				}
			}

			// Also check for og:description as fallback
			if n.Data == "meta" {
				var property, content string
				for _, attr := range n.Attr {
					if attr.Key == "property" && attr.Val == "og:description" {
						property = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if property == "og:description" && content != "" && description == "" {
					description = content
				}
			}
		}

		// Traverse child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	// Clean up extracted strings
	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)

	// Limit description length to prevent overly long responses
	if len(description) > 300 {
		description = description[:300] + "..."
	}

	return title, description
}

// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(host string) bool {
	ip := net.ParseIP(host)
	if ip == nil {
		return false
	}

	// Check for private IPv4 ranges
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 || // 10.0.0.0/8
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) || // 172.16.0.0/12
			(ip4[0] == 192 && ip4[1] == 168) || // 192.168.0.0/16
			ip4[0] == 127 || // 127.0.0.0/8 (loopback)
			ip4[0] == 0 || // 0.0.0.0/8
			(ip4[0] == 169 && ip4[1] == 254) // 169.254.0.0/16 (link-local)
	}

	// Check for IPv6 private ranges
	if ip.To16() != nil {
		// IPv6 loopback
		if ip.IsLoopback() {
			return true
		}
		// IPv6 link-local
		if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}
		// IPv6 unique local
		if len(ip) >= 2 && ip[0] == 0xfc && ip[1] == 0x00 {
			return true
		}
		// IPv6 documentation
		if len(ip) >= 2 && ip[0] == 0x20 && ip[1] == 0x01 && ip[2] == 0x0d && ip[3] == 0xb8 {
			return true
		}
	}

	return false
}

