// FetchURLPreview handles POST requests with JSON body containing a URL,
// fetches the HTML content, and extracts title and meta description.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set response content type to JSON
	ctx.SetContentType("application/json")

	// Only accept POST method
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		json.NewEncoder(ctx).Encode(URLPreview{
			Error: "Only POST method is allowed",
		})
		return
	}

	// Parse request body
	var req URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreview{
			Error: fmt.Sprintf("Invalid JSON: %v", err),
		})
		return
	}

	// Validate URL
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreview{
			Error: "URL is required",
		})
		return
	}

	// Fetch and parse HTML
	title, description, err := fetchAndParseHTML(req.URL)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(URLPreview{
			Error: fmt.Sprintf("Failed to fetch URL: %v", err),
		})
		return
	}

	// Return successful response
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(URLPreview{
		Title:       title,
		Description: description,
	})
}

// fetchAndParseHTML retrieves HTML content and extracts title and meta description
func fetchAndParseHTML(url string) (string, string, error) {
	// Create HTTP client with dual-stack dialer and 3-second timeout
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
		ReadTimeout: 3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	// Prepare request
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(url)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.SetUserAgent("URLPreviewBot/1.0")

	// Execute request with redirect following
	err := client.DoRedirects(req, resp, 10) // Allow up to 10 redirects
	if err != nil {
		return "", "", fmt.Errorf("HTTP request failed: %w", err)
	}

	// Check response status
	if statusCode := resp.StatusCode(); statusCode != fasthttp.StatusOK {
		return "", "", fmt.Errorf("HTTP status %d", statusCode)
	}

	// Parse HTML
	body := resp.Body()
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", "", fmt.Errorf("HTML parsing failed: %w", err)
	}

	// Extract title and description
	title := extractTitle(doc)
	description := extractMetaDescription(doc)

	return title, description, nil
}

// extractTitle traverses HTML nodes to find the title tag
func extractTitle(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
		return n.FirstChild.Data
	}
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if title := extractTitle(c); title != "" {
			return title
		}
	}
	return ""
}

// extractMetaDescription traverses HTML nodes to find meta description
func extractMetaDescription(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "meta" {
		var name, content string
		for _, attr := range n.Attr {
			if attr.Key == "name" && attr.Val == "description" {
				name = "description"
			} else if attr.Key == "content" {
				content = attr.Val
			}
		}
		if name == "description" && content != "" {
			return content
		}
	}
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if desc := extractMetaDescription(c); desc != "" {
			return desc
		}
	}
	return ""
}

// main function sets up the HTTP server and routes
func main() {
	// Define route handler
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	// Start server
	fmt.Println("Server starting on :8080")
	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		panic(fmt.Sprintf("Server failed: %v", err))
	}
}

