package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// isSafeHost checks if the host is not a private IP, localhost, or internal domain.
func isSafeHost(host string) bool {
	if host == "" {
		return false
	}
	// Check for localhost
	if strings.EqualFold(host, "localhost") {
		return false
	}
	// Parse IP address
	ip := net.ParseIP(host)
	if ip != nil {
		// Check for loopback and private IPs
		if ip.IsLoopback() || ip.IsPrivate() {
			return false
		}
		return true
	}
	// For domain names, check for common local patterns
	lowerHost := strings.ToLower(host)
	if strings.Contains(lowerHost, "localhost") || strings.Contains(lowerHost, ".local") || strings.Contains(lowerHost, ".internal") {
		return false
	}
	return true
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Validate host for SSRF protection
	if !isSafeHost(parsedURL.Hostname()) {
		ctx.Error("URL host is not allowed", fasthttp.StatusBadRequest)
		return
	}

	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		ReadTimeout:         2 * time.Second,
		WriteTimeout:        2 * time.Second,
		MaxIdleConnDuration: 2 * time.Second,
		MaxConnsPerHost:     2,
		Dial: func(addr string) (net.Conn, error) {
			return fasthttp.DialTimeout(addr, 2*time.Second)
		},
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	// Track visited URLs to prevent cycles
	visited := make(map[string]bool)
	currentURL := parsedURL
	visited[currentURL.String()] = true

	maxRedirects := 5
	redirectsFollowed := 0

	for {
		freq.SetRequestURI(currentURL.String())
		freq.Header.SetMethod("GET")
		freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
		freq.Header.Set("Accept", "text/html")
		freq.Header.Set("Accept-Language", "en-US,en;q=0.5")
		freq.Header.Set("Accept-Encoding", "gzip, deflate")

		if err := client.Do(freq, res); err != nil {
			ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
			return
		}

		statusCode := res.StatusCode()
		if statusCode >= 300 && statusCode < 400 && redirectsFollowed < maxRedirects {
			location := res.Header.Peek("Location")
			if len(location) == 0 {
				ctx.Error("Redirect without Location header", fasthttp.StatusBadGateway)
				return
			}

			newURLStr := string(location)
			newURL, err := url.Parse(newURLStr)
			if err != nil {
				ctx.Error("Invalid redirect URL format", fasthttp.StatusBadGateway)
				return
			}

			// Resolve relative URL
			if !newURL.IsAbs() {
				newURL = currentURL.ResolveReference(newURL)
			}

			// Validate scheme
			if newURL.Scheme != "http" && newURL.Scheme != "https" {
				ctx.Error("Redirect URL must use http or https scheme", fasthttp.StatusBadRequest)
				return
			}

			// Validate host for SSRF protection
			if !isSafeHost(newURL.Hostname()) {
				ctx.Error("Redirect URL host is not allowed", fasthttp.StatusBadRequest)
				return
			}

			// Check for redirect cycle
			if visited[newURL.String()] {
				ctx.Error("Redirect cycle detected", fasthttp.StatusBadRequest)
				return
			}

			// Update for next iteration
			currentURL = newURL
			visited[currentURL.String()] = true
			redirectsFollowed++

			// Reset request and response for next iteration
			freq.Reset()
			res.Reset()
			continue
		}
		break
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	contentType := string(res.Header.Peek("Content-Type"))
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.Error("URL does not return HTML content", fasthttp.StatusBadRequest)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
