	}

	// Fetch URL content
	title, description, err := fetchURLContent(url)
	if err != nil {
		sendError(ctx, fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Prepare and send response
	preview := URLPreview{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json")
	if err := json.NewEncoder(ctx).Encode(preview); err != nil {
		sendError(ctx, "Failed to encode response", fasthttp.StatusInternalServerError)
	}
}

// fetchURLContent fetches and parses HTML from the given URL
func fetchURLContent(url string) (string, string, error) {
	// Create fasthttp client with timeout and SSRF protection
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			return dialWithSSRFProtection(addr)
		},
		ReadTimeout:        5 * time.Second,
		WriteTimeout:       5 * time.Second,
		MaxConnDuration:    10 * time.Second,
		MaxIdleConnDuration: 30 * time.Second,
		MaxConnsPerHost:    2,
	}

	// Prepare request
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(url)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.SetUserAgent("URLPreviewBot/1.0")

	// Execute request with limited redirects
	if err := client.DoRedirects(req, resp, 3); err != nil {
		return "", "", fmt.Errorf("HTTP request failed: %w", err)
