package main

import (
	"encoding/json"
	"log"
	"strings"
	"time"

	"github.com/PuerkitoBio/goquery"
	"github.com/valyala/fasthttp"
)

// PreviewData holds the extracted title and description
type PreviewData struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles POST requests with JSON containing a URL,
// fetches the page, and extracts title and meta description
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetBodyString("Method not allowed")
		return
	}

	// Parse JSON request body
	var request struct {
		URL string `json:"url"`
	}
	if err := json.Unmarshal(ctx.PostBody(), &request); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetBodyString(`{"error":"Invalid JSON"}`)
		return
	}

	// Validate URL
	if request.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetBodyString(`{"error":"URL is required"}`)
		return
	}

	// Create HTTP client with timeout and dual-stack dialer
	client := &fasthttp.Client{
		Dial:          fasthttp.DialDualStack,
		ReadTimeout:   3 * time.Second,
		WriteTimeout:  3 * time.Second,
		MaxIdleConnDuration: 3 * time.Second,
	}

	// Prepare request
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(request.URL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch URL with redirect handling
	err := client.DoRedirects(req, resp, 5)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetBodyString(`{"error":"Failed to fetch URL"}`)
		return
	}

	// Check response status
	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetBodyString(`{"error":"URL returned non-200 status"}`)
		return
	}

	// Parse HTML
	body := resp.Body()
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(body)))
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetBodyString(`{"error":"Failed to parse HTML"}`)
		return
	}

	// Extract title
	title := doc.Find("title").First().Text()

	// Extract meta description
	description := ""
	doc.Find("meta[name='description']").Each(func(i int, s *goquery.Selection) {
		if content, exists := s.Attr("content"); exists {
			description = content
		}
	})

	// If no meta description found, try Open Graph description
	if description == "" {
		doc.Find("meta[property='og:description']").Each(func(i int, s *goquery.Selection) {
			if content, exists := s.Attr("content"); exists {
				description = content
			}
		})
	}

	// Prepare response
	preview := PreviewData{
		Title:       strings.TrimSpace(title),
		Description: strings.TrimSpace(description),
	}

	// Send JSON response
	ctx.SetContentType("application/json")
	if err := json.NewEncoder(ctx).Encode(preview); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetBodyString(`{"error":"Failed to encode response"}`)
		return
	}
}

func main() {
	// Register handler
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.SetBodyString("Not found")
		}
	}

	// Start server
	log.Println("Server starting on :8080")
	if err := fasthttp.ListenAndServe(":8080", handler); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

