// Request structure for incoming JSON
type URLRequest struct {
	URL string `json:"url"`
}

// Response structure for outgoing JSON
type URLPreview struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests with JSON body containing a URL,
// fetches the webpage, extracts title and meta description.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only accept POST requests
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetBodyString("Method not allowed")
		return
	}

	// Parse request body
	var req URLRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		sendError(ctx, "Invalid JSON format", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL
	if req.URL == "" {
		sendError(ctx, "URL field is required", fasthttp.StatusBadRequest)
		return
	}

	// Fetch and parse webpage
	preview, err := fetchAndParseURL(req.URL)
	if err != nil {
		sendError(ctx, fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Send successful response
	sendJSON(ctx, preview, fasthttp.StatusOK)
}

// fetchAndParseURL downloads webpage and extracts title/description
func fetchAndParseURL(rawURL string) (*URLPreview, error) {
	// Create HTTP client with timeout and dual-stack support
	client := &fasthttp.Client{
		Dial:               fasthttp.DialDualStack,
		MaxRedirectsCount: 10,
	}

	// Prepare request
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(rawURL)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Execute request with timeout and follow redirects
	timeout := 3 * time.Second
	if err := client.DoTimeout(req, resp, timeout); err != nil {
		return nil, fmt.Errorf("HTTP request failed: %w", err)
	}

	// Check response status
	if resp.StatusCode() != fasthttp.StatusOK {
		return nil, fmt.Errorf("HTTP status %d", resp.StatusCode())
	}

	// Parse HTML
	return parseHTML(resp.Body())
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(html []byte) (*URLPreview, error) {
	// Create goquery document
	doc, err := goquery.NewDocumentFromReader(strings.NewReader(string(html)))
	if err != nil {
		return nil, fmt.Errorf("failed to parse HTML: %w", err)
	}

	preview := &URLPreview{}

	// Extract title
	title := doc.Find("title").First().Text()
	preview.Title = strings.TrimSpace(title)

	// Extract meta description
	doc.Find("meta[name='description']").Each(func(i int, s *goquery.Selection) {
		if content, exists := s.Attr("content"); exists && preview.Description == "" {
			preview.Description = strings.TrimSpace(content)
		}
	})

	// Fallback to meta property og:description
	if preview.Description == "" {
		doc.Find("meta[property='og:description']").Each(func(i int, s *goquery.Selection) {
			if content, exists := s.Attr("content"); exists && preview.Description == "" {
				preview.Description = strings.TrimSpace(content)
			}
		})
	}

	// Return error if neither title nor description found
	if preview.Title == "" && preview.Description == "" {
		return nil, errors.New("no title or description found")
	}

	return preview, nil
}

// sendJSON sends a JSON response with given status code
func sendJSON(ctx *fasthttp.RequestCtx, data interface{}, statusCode int) {
	ctx.SetStatusCode(statusCode)
	ctx.SetContentType("application/json")
	if err := json.NewEncoder(ctx).Encode(data); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetBodyString(`{"error":"Failed to encode JSON response"}`)
	}
}

// sendError sends an error response in JSON format
func sendError(ctx *fasthttp.RequestCtx, message string, statusCode int) {
	sendJSON(ctx, URLPreview{Error: message}, statusCode)
}

