// isPrivateIP checks if an IP address is in a private range
func isPrivateIP(ip net.IP) bool {
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 ||
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) ||
			(ip4[0] == 192 && ip4[1] == 168) ||
			ip4[0] == 127
	}
	return ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast()
}

// validateURL checks if URL is safe to fetch (SSRF protection)
func validateURL(rawURL string) error {
	parsed, err := url.Parse(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL format")
	}

	// Only allow HTTP and HTTPS schemes
	if parsed.Scheme != "http" && parsed.Scheme != "https" {
		return fmt.Errorf("only http and https schemes are allowed")
	}

	// Resolve host to IP address
	host := parsed.Hostname()
	if host == "" {
		return fmt.Errorf("invalid host")
	}

	// Check for localhost or private IPs
	if strings.HasPrefix(host, "localhost") || 
	   strings.HasSuffix(host, ".localhost") ||
	   strings.HasPrefix(host, "127.") ||
	   strings.HasPrefix(host, "192.168.") ||
	   strings.HasPrefix(host, "10.") ||
	   strings.HasPrefix(host, "172.") ||
	   strings.Contains(host, "::1") ||
	   strings.Contains(host, "0.0.0.0") {
		return fmt.Errorf("access to local or private resources is not allowed")
	}

	// Resolve IP addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("cannot resolve host")
	}

	// Check all resolved IPs
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP ranges is not allowed")
		}
	}

	return nil
}

// FetchURLPreview handles POST requests to fetch URL metadata
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set content type for response
	ctx.SetContentType("application/json")

	// Only accept POST method
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		json.NewEncoder(ctx).Encode(URLPreview{
			Error: "Only POST method is allowed",
		})
		return
