	}

	var result strings.Builder
	var extractText func(*html.Node, bool)
	extractText = func(n *html.Node, insideParagraph bool) {
		if n.Type == html.TextNode && insideParagraph {
			text := strings.TrimSpace(n.Data)
			if text != "" && result.Len() < 200 {
				if result.Len() > 0 {
					result.WriteString(" ")
				}
				result.WriteString(text)
			}
		}

		isParagraph := n.Type == html.ElementNode && n.Data == "p"
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			extractText(c, insideParagraph || isParagraph)
		}
	}
	extractText(doc, false)

	return truncateString(result.String(), 200)
}

// truncateString limits string length and adds ellipsis if needed
func truncateString(s string, maxLen int) string {
	if len(s) <= maxLen {
		return s
	}
	return s[:maxLen-3] + "..."
}

func main() {
	// Register handler
	fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/fetch-url-preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	})
}

