// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Limit request body size to prevent DoS
	const maxRequestBodySize = 1024 * 10 // 10KB
	if len(ctx.PostBody()) > maxRequestBodySize {
		ctx.Error("Request body too large", fasthttp.StatusRequestEntityTooLarge)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// SSRF protection: Validate host is not internal/private
	if isPrivateHost(parsedURL.Hostname()) {
		ctx.Error("Access to private networks is not allowed", fasthttp.StatusForbidden)
		return
	}

	// Use fasthttp.Client with security configurations
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			return fasthttp.DialTimeout(addr, 10*time.Second)
		},
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 30 * time.Second,
		MaxConnsPerHost:     2,                     // Limit connections per host
		MaxResponseBodySize: 1024 * 1024 * 5,       // Limit response to 5MB
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html")
	freq.Header.Set("Accept-Language", "en-US,en;q=0.9")

	// Execute request with timeout
	if err := client.Do(freq, res); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Handle redirects manually with SSRF checks
	redirectCount := 0
	maxRedirects := 3
	for res.StatusCode() >= 300 && res.StatusCode() < 400 && redirectCount < maxRedirects {
		location := res.Header.Peek("Location")
		if len(location) == 0 {
			break
		}

		redirectURL, err := url.Parse(string(location))
		if err != nil {
			ctx.Error("Invalid redirect URL", fasthttp.StatusBadGateway)
			return
		}

		// Resolve relative URLs
		if !redirectURL.IsAbs() {
			redirectURL = parsedURL.ResolveReference(redirectURL)
		}

		// SSRF protection for redirects
		if isPrivateHost(redirectURL.Hostname()) {
			ctx.Error("Redirect to private network not allowed", fasthttp.StatusForbidden)
			return
		}

		freq.SetRequestURI(redirectURL.String())
		fasthttp.ReleaseResponse(res)
		res = fasthttp.AcquireResponse()

		if err := client.Do(freq, res); err != nil {
			ctx.Error(fmt.Sprintf("Failed to follow redirect: %v", err), fasthttp.StatusBadGateway)
			return
		}

		redirectCount++
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Validate content type is HTML
	contentType := string(res.Header.Peek("Content-Type"))
	if !strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.Error("URL does not return HTML content", fasthttp.StatusUnsupportedMediaType)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

