		return
	}

	// Check for private/internal IP addresses
	for _, ip := range ips {
		if isPrivateIP(ip) {
			ctx.Error("Access to private networks is not allowed", fasthttp.StatusForbidden)
			return
		}
	}

	// Create HTTP client with timeouts and dual-stack support
	client := &fasthttp.Client{
		Dial:             fasthttp.DialDualStack,
		ReadTimeout:      5 * time.Second,
		WriteTimeout:     5 * time.Second,
		MaxConnDuration:  10 * time.Second,
