		fasthttp.ReleaseResponse(httpResp)
	}()

	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)
	httpReq.Header.SetUserAgent("URLPreviewBot/1.0")
	httpReq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	// Execute request with redirect following and timeout
	if err := client.DoTimeout(httpReq, httpResp, 10*time.Second); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusInternalServerError)
