// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip net.IP) bool {
	// Check for IPv4 private ranges
	if ip4 := ip.To4(); ip4 != nil {
		return ip4[0] == 10 ||
			(ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31) ||
			(ip4[0] == 192 && ip4[1] == 168) ||
			ip4[0] == 127 // localhost
	}

	// Check for IPv6 private ranges
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for IPv6 unique local addresses (fc00::/7)
	if len(ip) == net.IPv6len && ip[0] == 0xfc {
		return true
	}

	return false
}

// extractPreview parses HTML to find title and meta description
func extractPreview(htmlContent []byte) (*urlPreview, error) {
	preview := &urlPreview{}
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return nil, err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Extract title from <title> tag
		if n.Type == html.ElementNode && n.Data == "title" && n.FirstChild != nil {
			preview.Title = strings.TrimSpace(n.FirstChild.Data)
		}

		// Extract description from <meta name="description"> tag
		if n.Type == html.ElementNode && n.Data == "meta" {
			var name, content string
			for _, attr := range n.Attr {
				if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
					name = attr.Val
				}
				if attr.Key == "content" {
					content = strings.TrimSpace(attr.Val)
				}
			}
			if name != "" && content != "" && preview.Description == "" {
				preview.Description = content
			}
		}

		// Continue traversing if we haven't found both values
		if preview.Title == "" || preview.Description == "" {
			for c := n.FirstChild; c != nil; c = c.NextSibling {
				traverse(c)
			}
		}
	}
	traverse(doc)

	// Fallback for missing description: use first paragraph
	if preview.Description == "" {
		doc, _ := html.Parse(strings.NewReader(string(htmlContent)))
		var findParagraph func(*html.Node)
		findParagraph = func(n *html.Node) {
			if n.Type == html.ElementNode && n.Data == "p" && n.FirstChild != nil {
				text := strings.TrimSpace(n.FirstChild.Data)
				if text != "" && len(text) > 10 && preview.Description == "" {
					preview.Description = text
					if len(preview.Description) > 200 {
						preview.Description = preview.Description[:200] + "..."
					}
				}
			}
			for c := n.FirstChild; c != nil; c = c.NextSibling {
				findParagraph(c)
			}
		}
		findParagraph(doc)
	}

	return preview, nil
}

func main() {
	// Register handler
	fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not found", fasthttp.StatusNotFound)
		}
	})
}

