		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
	}
}

// validateHost checks if host is safe (not internal/private)
func validateHost(host string) error {
	if host == "" {
		return fmt.Errorf("empty host")
	}

	// Check for localhost
	if strings.HasSuffix(host, ".localhost") || host == "localhost" {
		return fmt.Errorf("localhost not allowed")
	}

	// Try to parse as IP first
	if ip := net.ParseIP(host); ip != nil {
		if ip.IsLoopback() || ip.IsPrivate() {
			return fmt.Errorf("private IP not allowed")
		}
		return nil
	}

	// Resolve host to check IP addresses
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	addrs, err := net.DefaultResolver.LookupIPAddr(ctx, host)
	if err != nil {
		return fmt.Errorf("cannot resolve host: %v", err)
	}

	for _, addr := range addrs {
		ip := addr.IP
		if ip.IsLoopback() || ip.IsPrivate() {
			return fmt.Errorf("host resolves to private IP")
		}
	}

	return nil
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && content != "" {
					description = content
				}
			}
		}

		// Traverse children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)

	// Clean up title and description
	title = strings.TrimSpace(title)
	description = strings.TrimSpace(description)

	return title, description, nil
}

