	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// validateHost checks if the host is allowed (SSRF protection)
func validateHost(host string) error {
	// Check if host is empty
	if host == "" {
		return fmt.Errorf("empty host")
	}

	// Resolve IP to check if it's a private/internal IP
	ips, err := net.LookupIP(host)
	if err != nil {
		return err
	}

	for _, ip := range ips {
		// Check for private IP ranges
		if ip.IsPrivate() || ip.IsLoopback() || ip.IsUnspecified() {
			return fmt.Errorf("private/internal IP addresses are not allowed")
		}

		// Check for IPv4 private ranges
		if ipv4 := ip.To4(); ipv4 != nil {
			// Check for common private ranges
			if (ipv4[0] == 10) ||
				(ipv4[0] == 172 && ipv4[1] >= 16 && ipv4[1] <= 31) ||
				(ipv4[0] == 192 && ipv4[1] == 168) ||
				(ipv4[0] == 169 && ipv4[1] == 254) {
				return fmt.Errorf("private/internal IP addresses are not allowed")
			}
		}
	}

	return nil
}

// safeDial is a custom dial function that validates the destination
func safeDial(addr string) (net.Conn, error) {
	host, _, err := net.SplitHostPort(addr)
	if err != nil {
		// If SplitHostPort fails, try using the address as host
		host = addr
	}

	if err := validateHost(host); err != nil {
		return nil, err
	}

	return fasthttp.DialDualStack(addr)
}

// sanitizeText removes potentially dangerous characters to prevent XSS
func sanitizeText(text string) string {
	// Remove null bytes and control characters
	text = strings.Map(func(r rune) rune {
		if r < 32 || r == 127 {
			return -1
		}
		return r
	}, text)

	// Limit length to prevent DoS
	const maxLength = 1000
	if len(text) > maxLength {
		text = text[:maxLength]
	}

	return strings.TrimSpace(text)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	// Use a proper HTML parser in production
	// This is a simplified version for demonstration
	data, err := io.ReadAll(r)
	if err != nil {
		return "", "", err
	}

	content := string(data)

	// Extract title
	titleStart := strings.Index(content, "<title>")
	titleEnd := strings.Index(content, "</title>")
	if titleStart != -1 && titleEnd != -1 && titleEnd > titleStart {
		title = content[titleStart+7 : titleEnd]
	}

	// Extract meta description
	descPatterns := []string{
		`<meta\s+name="description"\s+content="([^"]*)"`,
		`<meta\s+content="([^"]*)"\s+name="description"`,
		`<meta\s+property="og:description"\s+content="([^"]*)"`,
		`<meta\s+content="([^"]*)"\s+property="og:description"`,
	}

	for _, pattern := range descPatterns {
		re, err := regexp.Compile(pattern)
		if err != nil {
			continue // skip invalid patterns, though they should be valid
		}
		matches := re.FindStringSubmatch(content)
		if matches != nil && len(matches) > 1 {
			description = matches[1]
			break
		}
	}

	return title, description, nil
}

