		preview := URLPreview{
			Error: fmt.Sprintf("Failed to parse HTML: %v", err),
		}
		sendJSONResponse(ctx, fasthttp.StatusInternalServerError, preview)
		return
	}

	// Return successful response
	sendJSONResponse(ctx, fasthttp.StatusOK, preview)
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(body []byte) (URLPreview, error) {
	preview := URLPreview{}
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return preview, err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				preview.Title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && content != "" {
					preview.Description = strings.TrimSpace(content)
				}
			}
		}

		// Traverse child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return preview, nil
}

// sendJSONResponse sends a JSON response with appropriate headers
func sendJSONResponse(ctx *fasthttp.RequestCtx, statusCode int, data interface{}) {
	ctx.SetStatusCode(statusCode)
	ctx.Response.Header.SetContentType("application/json")
	jsonBytes, _ := json.Marshal(data)
	ctx.SetBody(jsonBytes)
}

